const handleSubmit = async (e) => {
  e.preventDefault();
  if (!validateForm()) return;

  setLoading(true);
  setError("");
  setSuccess("");

  try {
    const payload = {
      mobile: formData.mobile,
      fullName: formData.fullName,
      email: formData.email,
      role: formData.role,
    };

    console.log("📩 Signup payload:", payload); // <-- FRONTEND DEBUG LOG

    const res = await axios.post(
      "http://localhost:8000/api/auth/signup",
      payload,
      { headers: { "Content-Type": "application/json" }, timeout: 10000 }
    );

    if (res.data && res.data.success) {
      setSuccess(res.data.message || "Signup successful");
      setError("");
      setTimeout(() => navigate("/login"), 700);
    } else {
      setError(res.data?.message || "Signup failed. Try again.");
    }
  } catch (err) {
    console.error("Signup request error:", err);
    if (err.response?.data?.message) setError(err.response.data.message);
    else if (err.code === "ECONNABORTED") setError("Request timed out. Check backend.");
    else if (err.request) setError("No response from server. Make sure backend is running.");
    else setError(err.message || "Unknown error during signup.");
  } finally {
    setLoading(false);
  }
};
